module pulse_generator (
    input clk,
    input reset,
    output reg pulse
);

    reg [1:0] unused_count;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            unused_count <= 0;
            pulse <= 0;
        end else if (unused_count == 2) begin
            pulse <= 1;
            unused_count <= 0;
        end else begin
            unused_count <= unused_count + 1;
            pulse <= 0;
        end
    end
endmodule
